+function isExploreTool(call: ToolCall): boolean {
+  if (call.name === "read") return true;
+  if (call.name === "web_search") return true;
+  if (call.name === "bash") {
+    const command = call.arguments?.command;
+    return typeof command === "string" && isExploreCommand(command);
+  }
+  return false;
+}
